const item = $input.first();

const text = item.json.candidates[0].content.parts[0].text;

const cleaned = text
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

const parsed = JSON.parse(cleaned);

// Get original Google Drive file metadata from the trigger node
const sourceFileName = $("New Job Screenshot Trigger").first().json.name || "";
const sourceFileId = $("New Job Screenshot Trigger").first().json.id || "";

// Fit score + priority classification
const fitScore = Number(parsed.fit_score || 0);

let priority = "Ignore";

if (fitScore >= 90) {
  priority = "Excellent";
} else if (fitScore >= 75) {
  priority = "Strong";
} else if (fitScore >= 60) {
  priority = "Medium";
} else if (fitScore >= 40) {
  priority = "Weak";
}

return [
  {
    json: {
      "Date Added": new Date().toLocaleDateString("en-GB"),
      "Company": parsed.company || "Unknown",
      "Role": parsed.role || "",
      "Job Link": "N/A",
      "Platform": parsed.platform || "Screenshot",
      "Status": "New",
      "Deadline": parsed.deadline || "N/A",
      "Follow-up Date": "N/A",
      "Email Sent?": "No",
      "Skills": Array.isArray(parsed.skills) ? parsed.skills.join(", ") : parsed.skills || "",
      "Experience Required": parsed.experience_required || "",
      "Remote Type": parsed.remote_type || "",
      "Fit Score": fitScore,
      "Priority": priority,
      "Summary": parsed.summary || "",
      "Fit Reason": parsed.fit_reason || "",
      "Missing Skills": Array.isArray(parsed.missing_skills) ? parsed.missing_skills.join(", ") : parsed.missing_skills || "",
      "Resume Points To Highlight": Array.isArray(parsed.resume_points_to_highlight) ? parsed.resume_points_to_highlight.join(", ") : parsed.resume_points_to_highlight || "",
      "Next Action": parsed.next_action || "",
      "Source File Name": sourceFileName,
      "Source File ID": sourceFileId
    }
  }
];

const currentJob = $("Parse AI Job Analysis").first().json;

const currentFileId = (currentJob["Source File ID"] || "").trim();
const currentCompany = (currentJob["Company"] || "").trim().toLowerCase();
const currentRole = (currentJob["Role"] || "").trim().toLowerCase();

let duplicateFound = false;
let duplicateReason = "";

for (const row of $input.all()) {
  const existingFileId = (row.json["Source File ID"] || "").trim();
  const existingCompany = (row.json["Company"] || "").trim().toLowerCase();
  const existingRole = (row.json["Role"] || "").trim().toLowerCase();

  // Skip empty placeholder rows from Always Output Data
  if (!existingFileId && !existingCompany && !existingRole) {
    continue;
  }

  if (currentFileId && existingFileId && existingFileId === currentFileId) {
    duplicateFound = true;
    duplicateReason = "Same Source File ID";
    break;
  }

  if (
    currentCompany &&
    currentRole &&
    existingCompany === currentCompany &&
    existingRole === currentRole
  ) {
    duplicateFound = true;
    duplicateReason = "Same Company and Role";
    break;
  }
}

return [
  {
    json: {
      ...currentJob,
      duplicate: duplicateFound,
      duplicateReason,
      currentFileId
    }
  }
];
